sub_queries.sql:
SELECT Composer, Composition FROM T9
UNION
SELECT Composer, Composition FROM T11;

SELECT Studio, Director
FROM T10
WHERE CAST(REPLACE(REPLACE(REPLACE(Revenue, '$', ''), ',', ''), ' ', '') AS REAL) = (
    SELECT MAX(CAST(REPLACE(REPLACE(REPLACE(Revenue, '$', ''), ',', ''), ' ', '') AS REAL))
    FROM T10
);

SELECT Title, Studio 
FROM T13 
WHERE Rank = (SELECT MIN(Rank) FROM T13);

SELECT Title, Studio, Domestic_gross
FROM T13
WHERE Rank BETWEEN 1 AND 2000;

SELECT Composer, Performers 
FROM T9 
WHERE Date BETWEEN '1950-01-01' AND '1979-12-31';

SELECT Country, Revenue, Admissions 
FROM T10 
WHERE Title IN (
    "The Bridge on the River Kwai", 
    "Mother India"
);

SELECT Title, Studio, Domestic_gross
FROM T13
WHERE Rank IN (1, 2, 3);

SELECT MIN(Year) AS Min_Year, MAX(Year) AS Max_Year
FROM (
  SELECT CAST(Year AS REAL) AS Year FROM T1
  UNION ALL
  SELECT CAST(Admissions AS REAL) AS Year FROM T10
);

SELECT Scientific_name, Common_name, Conservation_status FROM T20
UNION
SELECT Scientific_name, Common_name, Conservation_status FROM T21;
